        self.op = op  # for operators
        self.left = left  # for binop
        self.right = right  # for binop
        self.operand = operand  # for unary


def parse(expression):
    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    # Remove whitespace
    expression = expression.replace(" ", "")

    # Tokenizer
    def tokenize(s):
        tokens = []
        i = 0
        while i < len(s):
            if s[i].isdigit() or s[i] == ".":
                # Parse number
                start = i
                while i < len(s) and (s[i].isdigit() or s[i] == "."):
                    i += 1
                tokens.append(("NUMBER", s[start:i]))
            elif s[i] in "+-*/()":
                tokens.append(("OPERATOR", s[i]))
                i += 1
            else:
                raise ValueError(f"Invalid character: {s[i]}")
        return tokens

    tokens = tokenize(expression)
    if not tokens:
        raise ValueError("Invalid expression")

    # Parser using recursive descent
    def parse_expression():
        return parse_add_sub()

    def parse_add_sub():
        node = parse_mul_div()

        while tokens and tokens[0][0] == "OPERATOR" and tokens[0][1] in "+-":
            op = tokens.pop(0)[1]
            right = parse_mul_div()
            node = ASTNode("binop", op=op, left=node, right=right)

        return node

