        node = parse_unary()

        while tokens and tokens[0][0] == "OPERATOR" and tokens[0][1] in "*/":
            op = tokens.pop(0)[1]
            right = parse_unary()
            node = ASTNode("binop", op=op, left=node, right=right)

        return node

    def parse_unary():
        if tokens and tokens[0][0] == "OPERATOR" and tokens[0][1] == "-":
            tokens.pop(0)
            operand = parse_unary()
            return ASTNode("unary", op="-", operand=operand)
        else:
            return parse_primary()

    def parse_primary():
        if not tokens:
            raise ValueError("Unexpected end of expression")

        token_type, token_value = tokens[0]

        if token_type == "NUMBER":
            tokens.pop(0)
            return ASTNode("number", value=float(token_value))
        elif token_type == "OPERATOR" and token_value == "(":
            tokens.pop(0)  # consume '('
            node = parse_expression()
            if not tokens or tokens[0][0] != "OPERATOR" or tokens[0][1] != ")":
                raise ValueError("Unmatched parenthesis")
            tokens.pop(0)  # consume ')'
            return node
        else:
            raise ValueError(f"Unexpected token: {token_value}")

    # Check for unmatched parentheses
    paren_count = 0
    for token_type, token_value in tokens:
        if token_value == "(":
            paren_count += 1
        elif token_value == ")":
            paren_count -= 1
            if paren_count < 0:
                raise ValueError("Unmatched parenthesis")

    if paren_count != 0:
        raise ValueError("Unmatched parenthesis")

    result = parse_expression()
    if tokens:
        raise ValueError("Invalid expression")

    return result


